mapper.select:
SELECT id, project_id, version_name, file_name, original_file_name, file_path, file_type, file_size, parse_status, index_status, parsed_content, content_hash, description, error_message, deleted, created_at, updated_at FROM prd_document WHERE project_id = #{projectId} AND deleted = false
AND version_name = #{versionName}
ORDER BY created_at DESC
